import os
import httpx
from mcp.server import Server
from mcp.types import Tool, TextContent

app = Server("github-server")
TOKEN = os.environ["GITHUB_TOKEN"]   # read once at startup

@app.list_tools()
async def list_tools():
    return [
        Tool(
            name="list_repos",
            description="List repositories for a GitHub user",
            inputSchema={
                "type": "object",
                "properties": {
                    "username": {"type": "string"},
                },
                "required": ["username"],
                # No "token" parameter — never ask the model for credentials
            },
        )
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name == "list_repos":
        username = arguments["username"]
        # Token is injected server-side from env — not from arguments
        headers = {"Authorization": f"Bearer {TOKEN}"}
        async with httpx.AsyncClient() as client:
            r = await client.get(
                f"https://api.github.com/users/{username}/repos",
                headers=headers,
            )
        repos = [repo["full_name"] for repo in r.json()]
        return [TextContent(type="text", text="\n".join(repos))]

import os
from pathlib import Path
from mcp.types import TextContent, CallToolResult

# Allowlist: server only sees files inside this directory
ALLOWED_ROOT = Path(os.environ.get("FS_ROOT", "/workspace")).resolve()

def safe_path(user_path: str) -> Path:
    """Resolve path and reject anything outside ALLOWED_ROOT."""
    resolved = (ALLOWED_ROOT / user_path).resolve()
    if not str(resolved).startswith(str(ALLOWED_ROOT)):
        raise ValueError(f"Path traversal attempt: {user_path!r}")
    return resolved

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name == "read_file":
        try:
            path = safe_path(arguments["path"])
        except ValueError as exc:
            return CallToolResult(
                content=[TextContent(type="text", text=str(exc))],
                isError=True,
            )
        if not path.exists():
            return CallToolResult(
                content=[TextContent(type="text", text=f"File not found: {path}")],
                isError=True,
            )
        return [TextContent(type="text", text=path.read_text(errors="replace"))]

    if name == "write_file":
        # Even write_file rejects paths outside the allowed root
        try:
            path = safe_path(arguments["path"])
        except ValueError as exc:
            return CallToolResult(
                content=[TextContent(type="text", text=str(exc))],
                isError=True,
            )
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(arguments["content"])
        return [TextContent(type="text", text=f"Written {path}")]

import asyncpg, os

# Create a read-only PostgreSQL role and use its credentials here
READ_ONLY_DSN = os.environ["PG_READONLY_URL"]   # postgresql://readonly_role:pass@host/db

@app.call_tool()
async def call_tool(name: str, arguments: dict):
    if name == "query":
        sql = arguments["sql"].strip()
        # Block write statements at the server level too
        first_word = sql.split()[0].upper() if sql else ""
        if first_word not in ("SELECT", "WITH", "EXPLAIN"):
            return CallToolResult(
                content=[TextContent(type="text", text="Only SELECT queries allowed")],
                isError=True,
            )
        conn = await asyncpg.connect(READ_ONLY_DSN)
        try:
            rows = await conn.fetch(sql)
            return [TextContent(type="text", text=str(list(rows)))]
        finally:
            await conn.close()

import hmac, os
from starlette.responses import Response

VALID_TOKENS = set(os.environ.get("MCP_TOKENS", "").split(","))

def verify_token(request) -> bool:
    auth = request.headers.get("Authorization", "")
    if not auth.startswith("Bearer "):
        return False
    token = auth[len("Bearer "):]
    # Constant-time comparison to prevent timing attacks
    return any(hmac.compare_digest(token, valid) for valid in VALID_TOKENS)

async def handle_sse(request):
    if not verify_token(request):
        return Response("Unauthorized", status_code=401)
    async with sse.connect_sse(request.scope, request.receive, request._send) as (r, w):
        await app.run(r, w, app.create_initialization_options())

