import re

def validate_username(value: object) -> str:
    """Accept only alphanumeric GitHub usernames."""
    if not isinstance(value, str):
        raise ValueError("username must be a string")
    if not re.fullmatch(r"[A-Za-z0-9](?:[A-Za-z0-9-]{0,38}[A-Za-z0-9])?", value):
        raise ValueError(f"Invalid GitHub username: {value!r}")
    return value

def validate_limit(value: object, max_value: int = 50) -> int:
    if not isinstance(value, (int, float)):
        raise ValueError("limit must be an integer")
    n = int(value)
    if not (1 <= n <= max_value):
        raise ValueError(f"limit must be between 1 and {max_value}, got {n}")
    return n

